svg.script:
(function() {
  var svg  = document.getElementById('root');
  var caEl = document.getElementById('ca');
  var tip    = document.getElementById('tip-layer');
  var tipBg  = document.getElementById('tip-bg');
  var tipBdr = document.getElementById('tip-bdr');
  var tipTip = document.getElementById('tip-tip');
  var tipVal = document.getElementById('tip-val');
  var tipLbl = document.getElementById('tip-lbl');

  /* §2 — isDark hoisted before all build and animation code */
  var isDark = false;

  var pad  = 20;   // horizontal padding each side
  var bh   = 52;   // bubble body height
  var rx   = 9;    // corner radius (matches reference)
  var tail = 8;    // tail length
  var tw   = 8;    // half-width of tail opening

  function showTip(cx, barTopY, valStr, lblStr) {
    // 1. Set text content first
    tipVal.textContent = valStr;
    tipLbl.textContent = lblStr;

    // 2. Measure actual rendered widths with getBBox()
    var valW = tipVal.getBBox().width + pad * 2;
    var lblW = tipLbl.getBBox().width + pad * 2;
    var hw   = Math.max(valW, lblW, 60) / 2;  // half-width, min 60px total

    // 3. Clamp tx so bubble never exits card edges
    var tx = Math.max(hw + 8, Math.min(cx, 1100 - hw - 8));

    // 4. Bubble sits ABOVE the bar by default (tail points down toward bar).
    //    ty = top edge of bubble body in SVG coords.
    //    Bubble occupies ty..(ty+bh), tail extends from (ty+bh) down to (ty+bh+tail).
    var ty = barTopY - tail - bh - 4;
    var flip = ty < 90;   // not enough headroom — flip below bar
    if (flip) ty = barTopY + tail + 4;

    // 5. Position group at (tx, ty) — local y=0 is top of bubble body
    tip.setAttribute('transform', 'translate(' + tx + ',' + ty + ')');

    // 6. Background rect (no stroke — just fills the interior)
    tipBg.setAttribute('x', -hw);
    tipBg.setAttribute('y', 0);
    tipBg.setAttribute('width', hw * 2);
    tipBg.setAttribute('height', bh);
    tipBg.setAttribute('rx', rx);

    // 7. Open-bottom border path — traces the rounded rect but leaves a gap
    //    of 2*tw at the bottom centre where the tail will connect.
    //    Mirrors the reference exactly: start at gap-right, go CCW around top,
    //    end at gap-left. No line drawn across the bottom between the two points.
    //
    //    Reference pattern (local coords, bubble above, tail below at y=bh):
    //      M  tw, bh          <- gap right edge (tail root)
    //      L  (hw-rx), bh     <- bottom-right straight
    //      Q  hw, bh  hw, (bh-rx)   <- bottom-right corner
    //      L  hw, rx          <- right side
    //      Q  hw, 0  (hw-rx), 0     <- top-right corner
    //      L -(hw-rx), 0      <- top straight
    //      Q -hw, 0  -hw, rx  <- top-left corner
    //      L -hw, (bh-rx)     <- left side
    //      Q -hw, bh  -(hw-rx), bh  <- bottom-left corner
    //      L -tw, bh          <- gap left edge (tail root)
    //    (path intentionally left open — no Z)
    var bdrPath, tipPath;
    if (!flip) {
      // tail below — gap on bottom edge
      bdrPath =
        'M' + tw + ',' + bh +
        ' L' + (hw - rx) + ',' + bh +
        ' Q' + hw + ',' + bh + ' ' + hw + ',' + (bh - rx) +
        ' L' + hw + ',' + rx +
        ' Q' + hw + ',0 ' + (hw - rx) + ',0' +
        ' L' + -(hw - rx) + ',0' +
        ' Q' + (-hw) + ',0 ' + (-hw) + ',' + rx +
        ' L' + (-hw) + ',' + (bh - rx) +
        ' Q' + (-hw) + ',' + bh + ' ' + -(hw - rx) + ',' + bh +
        ' L' + (-tw) + ',' + bh;
      // tail: right-gap → tip → left-gap
      tipPath =
        'M' + tw + ',' + bh +
        ' L0,' + (bh + tail) +
        ' L' + (-tw) + ',' + bh;
    } else {
      // tail above — gap on top edge (flipped)
      bdrPath =
        'M' + (-tw) + ',0' +
        ' L' + -(hw - rx) + ',0' +
        ' Q' + (-hw) + ',0 ' + (-hw) + ',' + rx +
        ' L' + (-hw) + ',' + (bh - rx) +
        ' Q' + (-hw) + ',' + bh + ' ' + -(hw - rx) + ',' + bh +
        ' L' + (hw - rx) + ',' + bh +
        ' Q' + hw + ',' + bh + ' ' + hw + ',' + (bh - rx) +
        ' L' + hw + ',' + rx +
        ' Q' + hw + ',0 ' + (hw - rx) + ',0' +
        ' L' + tw + ',0';
      tipPath =
        'M' + (-tw) + ',0' +
        ' L0,' + (-tail) +
        ' L' + tw + ',0';
    }
    tipBdr.setAttribute('d', bdrPath);
    tipTip.setAttribute('d', tipPath);

    // 8. Text positions centred vertically in the bubble body
    tipVal.setAttribute('x', 0);
    tipVal.setAttribute('y', bh * 0.35);
    tipLbl.setAttribute('x', 0);
    tipLbl.setAttribute('y', bh * 0.72);

    tip.style.opacity = '1';
  }

  function hideTip() {
    tip.style.opacity = '';
  }

  var bwEls = Array.prototype.slice.call(document.querySelectorAll('.bw'));
  bwEls.forEach(function(bw) {
    bw.addEventListener('mouseenter', function() {
      if (caEl) caEl.classList.add('hovering');
      bwEls.forEach(function(x) { x.classList.remove('active'); }); /* §4 clear stale */
      bw.classList.add('active');
      showTip(
        parseFloat(bw.getAttribute('data-cx')),
        parseFloat(bw.getAttribute('data-barty')),
        bw.getAttribute('data-val'),
        bw.getAttribute('data-lbl')
      );
    });
    bw.addEventListener('mouseleave', function() {
      bw.classList.remove('active');
      if (caEl) caEl.classList.remove('hovering');
      hideTip();
    });
  });

  /* §3/§4 — gate hover on .ready after last bar animation completes */
  var BAR_COUNT   = 11;
  var BAR_STAGGER = Math.min(0.25, 1.0 / BAR_COUNT); /* adaptive: ~0.091s */
  var BAR_DUR     = 0.8;
  var lastBarDelay = (BAR_COUNT - 1) * BAR_STAGGER;
  setTimeout(function() { if (caEl) caEl.classList.add('ready'); },
    (lastBarDelay + BAR_DUR + 0.1) * 1000);

  /* Dark toggle */
  function setMode(wantDark) {
    if (wantDark === isDark) return;
    isDark = wantDark;
    var thumb = document.getElementById('tthumb');
    var lbl   = document.getElementById('tlabel');
    if (wantDark) {
      svg.classList.add('dark');
      if (thumb) thumb.setAttribute('cx', '52');
      if (lbl)   lbl.textContent = 'Light';
    } else {
      svg.classList.remove('dark');
      if (thumb) thumb.setAttribute('cx', '16');
      if (lbl)   lbl.textContent = 'Dark';
    }
  }
  document.getElementById('dark-toggle').addEventListener('click', function() { setMode(!isDark); });

  /* Print toggle */
  document.getElementById('print-toggle').addEventListener('click', function() {
    var thumb = document.getElementById('pthumb');
    var lbl   = document.getElementById('plabel');
    if (svg.classList.toggle('print')) {
      thumb.setAttribute('cx', '52');
      lbl.textContent = 'Screen';
    } else {
      thumb.setAttribute('cx', '16');
      lbl.textContent = 'Print';
    }
  });

  /* Inter-frame dark mode sync */
  window.setMode = setMode;
  window.addEventListener('message', function(e) {
    if (e.data && e.data.type === 'setMode') setMode(e.data.dark);
  });
  setMode(window.location.href.indexOf('theme=dark') !== -1);
})();
